-- Bendito Café - Sprint 6: alinhamento com Cardápio BC 2025
-- Rode este SQL no Supabase depois de subir os arquivos da Sprint 6.
-- Ele sincroniza nomes, descrições, preços e imagens usados pela função segura create_public_order.

on conflict (id) do update set
  name = excluded.name,
  description = excluded.description,
  price = excluded.price,
  group_name = excluded.group_name,
  subgroup = excluded.subgroup,
  badge = excluded.badge,
  image_url = excluded.image_url,
  active = excluded.active,
  updated_at = now();
